code = """import json, re
from collections import defaultdict
# load businesses
path = var_call_bC8pABsUSjz4LtTsWdS3euDX
with open(path, 'r') as f:
    businesses = json.load(f)

cat_map = defaultdict(list)

for b in businesses:
    attrs = b.get('attributes')
    if not isinstance(attrs, dict):
        continue
    bac = attrs.get('BusinessAcceptsCreditCards')
    if not (isinstance(bac, str) and bac.strip().lower() == 'true'):
        continue
    bid = b.get('business_id')
    if not bid:
        continue
    bref = bid.replace('businessid_','businessref_')
    extracted = []
    cats = b.get('categories')
    if cats:
        if isinstance(cats, list):
            extracted = cats
        else:
            extracted = [c.strip() for c in str(cats).split(',') if c.strip()]
    if not extracted:
        desc = (b.get('description') or '').strip()
        if desc:
            idx = desc.lower().find('offers')
            if idx != -1:
                seg = desc[idx:idx+500]
                seg = seg.split('.',1)[0]
            else:
                seg = desc.split('.',1)[0]
            parts = re.split(',| and |;|/|\\band\\b', seg)
            for p in parts:
                p2 = p
                # remove common leading phrases
                for lead in ['offers a range of services in','offers a wide range of services in','offers a range of services, including','offers a wide range of services, including','offers','offering','providing','provides','services in','in','including',':']:
                    try:
                        p2 = p2.replace(lead, '')
                    except Exception:
                        pass
                p2 = p2.strip()
                if not p2:
                    continue
                if re.search(r"\d", p2):
                    continue
                if len(p2) > 80:
                    continue
                p2 = re.sub(r"\s+Services?$", '', p2, flags=re.I).strip()
                if p2:
                    extracted.append(p2)
    if not extracted:
        cat_map['Unknown'].append(bref)
    else:
        for c in extracted:
            c2 = re.sub(r"\s+Services?$", '', c, flags=re.I).strip()
            if c2:
                cat_map[c2].append(bref)

# dedupe lists
cat_map = {k: sorted(list(set(v))) for k,v in cat_map.items()}
# compute counts excluding Unknown
counts = {k: len(v) for k,v in cat_map.items() if k.lower() != 'unknown'}
if counts:
    top_cat = max(counts.items(), key=lambda x: x[1])[0]
    top_count = counts[top_cat]
    top_refs = cat_map[top_cat]
else:
    top_cat = None
    top_count = 0
    top_refs = []

out = {'top_category': top_cat, 'count': top_count, 'business_refs': top_refs, 'unknown_count': len(cat_map.get('Unknown', []))}
print('__RESULT__:')
print(json.dumps(out))"""

